const input = $('Workflow Input').item.json;
const orders = $input.all();

if (!orders || orders.length === 0) {
  return [{
    json: {
      found: false,
      message: `Nie znaleziono zamówienia${input.order_number ? ' o numerze ' + input.order_number : ''}${input.email ? ' dla adresu email ' + input.email : ''}.`
    }
  }];
}

const formatStatus = (status) => {
  const statusMap = {
    'new': 'Nowe - oczekuje na realizację',
    'processing': 'W trakcie realizacji',
    'shipped': 'Wysłane',
    'delivered': 'Dostarczone',
    'returned': 'Zwrócone'
  };
  return statusMap[status] || status;
};

const formatOrder = (order) => {
  let items = order.items;
  if (typeof items === 'string') {
    items = JSON.parse(items);
  }

  const itemsList = items.map(item => 
    `- ${item.name} (${item.variant || ''}) x${item.quantity} - ${item.price} PLN`
  ).join('\n');

  return {
    order_number: order.order_number,
    customer_name: order.customer_name,
    status: formatStatus(order.status),
    status_raw: order.status,
    items: itemsList,
    total: `${order.total} PLN`,
    shipping_method: order.shipping_method,
    tracking_number: order.tracking_number || 'Brak (zamówienie jeszcze nie wysłane)',
    carrier: order.carrier,
    created_at: new Date(order.created_at).toLocaleDateString('pl-PL')
  };
};

if (orders.length === 1) {
  const order = formatOrder(orders[0].json);
  return [{
    json: {
      found: true,
      single_order: true,
      ...order
    }
  }];
} else {
  const formattedOrders = orders.map(o => formatOrder(o.json));
  return [{
    json: {
      found: true,
      single_order: false,
      orders_count: formattedOrders.length,
      orders: formattedOrders.map(o => ({
        order_number: o.order_number,
        status: o.status,
        total: o.total,
        created_at: o.created_at
      }))
    }
  }];
}
